import java.util.*; import java.util.stream.*; class Student3{ String name; int mark; Student3(String n,int m){name=n;mark=m;} } public class Nine{ public static void main(String[] args){ List<Student3> list=Arrays.asList(new Student3("Ali",90),new Student3("Sara",85),new Student3("John",95),new Student3("Tom",80)); list.stream().sorted((a,b)->b.mark-a.mark).limit(3).forEach(s->System.out.println(s.name)); }}